mapper.insert:
insert into goods_category_detail (goodsCategoryId, nextCategoryName, createdDate ,nextCategoryImg
  )
values (#{goodsCategoryId,jdbcType=BIGINT}, #{nextCategoryName,jdbcType=VARCHAR}, #{createdDate,jdbcType=TIMESTAMP}, #{nextCategoryImg,jdbcType=VARCHAR}
  )

mapper.update:
update goods_category
set typeName = #{typeName,jdbcType=VARCHAR},
  createdDate = #{createdDate,jdbcType=TIMESTAMP}
where goodsCategoryId = #{goodsCategoryId,jdbcType=BIGINT}

mapper.select:
SELECT d.*,c.categoryName,s.`name`,s.imgUrl,concat(s.price,'') as price,s.goodsId,s.carouselImgUrl,s.remarkImgUrl from goods_category_detail d
LEFT JOIN goods_category c ON c.goodsCategoryId = d.goodsCategoryId
LEFT JOIN goods s ON s.categoryId = d.id

  
    AND d.id = #{id}
  
  
    AND c.goodsCategoryId=#{goodsCategoryId}
  
  AND s.name!=""

AND status =1 AND deleteStatus =0
GROUP BY goodsId
ORDER BY s.createdDate DESC LIMIT #{offset}, #{limit}

select count(1) from (SELECT name from goods_category_detail d LEFT JOIN goods_category c ON c.goodsCategoryId = d.goodsCategoryId LEFT JOIN goods s ON s.categoryId = d.id
AND d.id = #{id}
AND c.goodsCategoryId=#{goodsCategoryId}
AND status =1 AND deleteStatus =0 GROUP BY s.goodsId)a
